previewCss:
.darma-loader-darma-custom-439 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: #7dd3fc;
  --loader-bg: #ffffff;
  width: 55px;
  aspect-ratio: 1;
  --g1: conic-gradient(from 90deg at top 3px left 3px,#0000 90deg,var(--loader-bg, #ffffff) 0);
  --g2: conic-gradient(from -90deg at bottom 3px right 3px,#0000 90deg,var(--loader-bg, #ffffff) 0);
  background:var(--g1),var(--g1),var(--g1),var(--g1),var(--g2),var(--g2),var(--g2),var(--g2);
  background-position: 0 0,100% 0,100% 100%,0 100%;
  background-size: 25px 25px;
  background-repeat: no-repeat;
  animation: darma-loader-darma-custom-439-l11 1.5s infinite;
}@keyframes darma-loader-darma-custom-439-l11 {0% {background-size:35px 15px,15px 15px,15px 35px,35px 35px}25% {background-size:35px 35px,15px 35px,15px 15px,35px 15px}50% {background-size:15px 35px,35px 35px,35px 15px,15px 15px}75% {background-size:15px 15px,35px 15px,35px 35px,15px 35px}100% {background-size:35px 15px,15px 15px,15px 35px,35px 35px}}

